  || responseData.message
  || responseData.error
  || '';

const hasProviderError = !!providerErrorMessage && !providerMessageId;
const envioOk = !!providerMessageId && !hasProviderError;

const campaignId = String(leadData.campaignId || $env.CAMPAIGN_ID || `campanha_${new Date().toISOString().slice(0, 10)}`);
const csvStateKey = String(leadData.csv_state_key || '');
