const killSwitchThreshold = Math.max(1, Number($env.CAMPAIGN_KILL_SWITCH_ERRORS || 3));

const staticData = $getWorkflowStaticData('global');

if (csvStateKey && Number.isInteger(rowIndex) && rowIndex >= 0) {
  const state = staticData[csvStateKey];
  if (state && Array.isArray(state.rows) && state.rows[rowIndex]) {
    const finalStatus = envioOk ? 'Enviado' : 'Nao Enviado';
    state.rows[rowIndex][statusColumn] = finalStatus;
    state.rows[rowIndex].status_campanha = finalStatus;
    state.rows[rowIndex].status_programacao = finalStatus;
    state.rows[rowIndex][statusIdColumn] = campaignId;
    state.rows[rowIndex].campanha_status_id = campaignId;
    staticData[csvStateKey] = state;
  }
}

let consecutiveErrors = 0;
let killSwitchStop = false;
let killSwitchReason = '';

if (runtimeKey) {
  const runtime = staticData[runtimeKey] || {
    consecutiveErrors: 0,
    totalErrors: 0,
    totalSent: 0,
    killSwitchTriggered: false,
  };

  if (envioOk) {
    runtime.consecutiveErrors = 0;
    runtime.totalSent = Number(runtime.totalSent || 0) + 1;
  } else {
    runtime.consecutiveErrors = Number(runtime.consecutiveErrors || 0) + 1;
    runtime.totalErrors = Number(runtime.totalErrors || 0) + 1;
  }

  consecutiveErrors = Number(runtime.consecutiveErrors || 0);
  killSwitchStop = !envioOk && consecutiveErrors >= killSwitchThreshold;

  if (killSwitchStop) {
    killSwitchReason = `${consecutiveErrors} erros consecutivos no envio`;
    runtime.killSwitchTriggered = true;
    runtime.killSwitchReason = killSwitchReason;
    runtime.killSwitchAt = new Date().toISOString();
