const staticData = $getWorkflowStaticData('global');
const stateKey = `campaign_csv_state_${executionId}`;
const state = staticData[stateKey];

if (!state || !Array.isArray(state.rows) || !Array.isArray(state.headerKeys) || !state.path) {
  return [{
    json: {
      persistencia_csv: false,
      message: 'estado_csv_nao_encontrado',
      stateKey,
    }
  }];
}

const csvEscape = (value) => {
  const str = String(value ?? '');
  if (/[",\n\r]/.test(str)) {
    return `"${str.replace(/"/g, '""')}"`;
  }
  return str;
};

const lines = [];
lines.push(state.headerKeys.map((key) => csvEscape(key)).join(','));

for (const row of state.rows) {
  lines.push(state.headerKeys.map((key) => csvEscape(row[key])).join(','));
}

fs.writeFileSync(state.path, lines.join('\n'), 'utf8');
delete staticData[stateKey];

return [{
  json: {
    persistencia_csv: true,
    arquivo_csv: state.path,
    total_linhas: state.rows.length,
    execution_id: executionId,
    atualizado_em: new Date().toISOString(),
